// ── Notion: HTTP cru + paginação (this.helpers vem do runtime do Code node) ──
const NOTION_TOKEN = $env.NOTION_TOKEN;
const NOTION_VERSION = $env.NOTION_VERSION || '2022-06-28';
const HELPERS = this.helpers;
function notionHeaders() {
  return { Authorization: `Bearer ${NOTION_TOKEN}`, 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' };
}
async function notionQueryAll(databaseId, filter, sorts) {
  let results = [];
  let cursor;
  do {
    const body = { page_size: 100 };
    if (filter) body.filter = filter;
    if (sorts) body.sorts = sorts;
    if (cursor) body.start_cursor = cursor;
    const resp = await HELPERS.httpRequest({
      method: 'POST',
      url: `https://api.notion.com/v1/databases/${databaseId}/query`,
      headers: notionHeaders(),
      body,
      json: true,
    });
    results = results.concat(resp.results || []);
    cursor = resp.has_more ? resp.next_cursor : null;
  } while (cursor);
  return results;
}
async function notionCreatePage(databaseId, properties) {
  return HELPERS.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: notionHeaders(),
    body: { parent: { database_id: databaseId }, properties },
    json: true,
  });
}
async function notionUpdatePage(pageId, properties) {
  return HELPERS.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/pages/${pageId}`,
    headers: notionHeaders(),
    body: { properties },
    json: true,
  });
}

// ── Glue: lê Dicionário (origem=cartao) e Lançamentos (origem=cartao, p/ dedup) ──
const filtroCartao = { property: 'Origem', select: { equals: 'cartao' } };
const [dicionario, lancamentosExistentes] = await Promise.all([
  notionQueryAll($env.NOTION_DB_DICIONARIO, filtroCartao),
  notionQueryAll($env.NOTION_DB_LANCAMENTOS, filtroCartao),
]);
return [{ json: { dicionario, lancamentos_existentes: lancamentosExistentes } }];

// Parser da fatura C6 cartão — lógica pura do Code node do workflow ingestao-csv-cartao.
// Implementa gstack/plans/ingestao-csv-cartao.md. Sem dependências externas.

const COLUNAS = [
  "Data de Compra", "Nome no Cartão", "Final do Cartão", "Categoria", "Descrição",
  "Parcela", "Valor (em US$)", "Cotação (em R$)", "Valor (em R$)",
];

/** Divide uma linha CSV com separador ; respeitando campos entre aspas. */
function splitLinha(linha) {
  const campos = [];
  let atual = "";
  let dentroAspas = false;
  for (let i = 0; i < linha.length; i++) {
    const c = linha[i];
    if (c === '"') {
      if (dentroAspas && linha[i + 1] === '"') { atual += '"'; i++; }
      else dentroAspas = !dentroAspas;
    } else if (c === ";" && !dentroAspas) {
      campos.push(atual); atual = "";
    } else {
      atual += c;
    }
  }
  campos.push(atual);
  return campos.map((c) => c.trim());
}

/** DD/MM/YYYY → Date (para ordenação por proximidade). */
function paraData(ddmmyyyy) {
  const [d, m, a] = ddmmyyyy.split("/").map(Number);
  const data = new Date(a, m - 1, d);
  if (Number.isNaN(data.getTime())) throw new Error(`data inválida: ${ddmmyyyy}`);
  return data;
}

/** Extrai a data de vencimento de "Fatura_YYYY-MM-DD.csv". Lança erro se fora do padrão. */
function vencimentoDoNome(nomeArquivo) {
  const m = /Fatura_(\d{4})-(\d{2})-(\d{2})\.csv$/i.exec(nomeArquivo);
  if (!m) throw new Error(`nome de arquivo fora do padrão Fatura_YYYY-MM-DD.csv: ${nomeArquivo}`);
  return `${m[3]}/${m[2]}/${m[1]}`; // DD/MM/YYYY
}

/**
 * Cancela pares 1:1 (estorno negativo + positivo de mesma descrição e |valor|,
 * o mais próximo em data). Retorna { mantidos, cancelados }.
 */
function cancelarPares(linhas) {
  const mantidos = [...linhas];
  const cancelados = [];
  const ehParAnuidade = (neg, pos) =>
    neg["Descrição"] === "Estorno Tarifa" && pos["Descrição"].startsWith("Anuidade");

  for (const neg of linhas.filter((l) => l._valor < 0)) {
    if (!mantidos.includes(neg)) continue;
    const candidatos = mantidos.filter(
      (pos) =>
        pos._valor > 0 &&
        Math.abs(pos._valor) === Math.abs(neg._valor) &&
        (pos["Descrição"] === neg["Descrição"] || ehParAnuidade(neg, pos))
    );
    if (candidatos.length === 0) continue;
    candidatos.sort(
      (a, b) =>
        Math.abs(paraData(a["Data de Compra"]) - paraData(neg["Data de Compra"])) -
        Math.abs(paraData(b["Data de Compra"]) - paraData(neg["Data de Compra"]))
    );
    const par = candidatos[0];
    mantidos.splice(mantidos.indexOf(neg), 1);
    mantidos.splice(mantidos.indexOf(par), 1);
    cancelados.push({
      estorno: { descricao: neg["Descrição"], data: neg["Data de Compra"], valor: neg._valor },
      original: { descricao: par["Descrição"], data: par["Data de Compra"], valor: par._valor },
    });
  }
  return { mantidos, cancelados };
}

/** Busca categoria no dicionário: descrição CONTÉM chave (case-insensitive). */
function categorizar(descricao, dicionario) {
  const alvo = descricao.toUpperCase();
  const regra = dicionario.find((r) => alvo.includes(r.chave.toUpperCase()));
  return regra ? regra.categoria : "";
}

/**
 * Processa a fatura completa.
 * @param {string} csvText conteúdo do CSV (UTF-8)
 * @param {string} nomeArquivo ex.: Fatura_2026-06-10.csv
 * @param {{chave: string, categoria: string}[]} dicionario regras origem=cartao
 * @param {{nome: string}[]} metas metas ativas (aba Metas)
 * @returns {{lancamentos: object[], cancelados: object[], avisos: string[], resumo: object}}
 */
function processarFatura(csvText, nomeArquivo, dicionario, metas) {
  const vencimento = vencimentoDoNome(nomeArquivo);
  const linhasTexto = csvText.replace(/^﻿/, "").split(/\r?\n/).filter((l) => l.trim() !== "");
  if (linhasTexto.length === 0) throw new Error("CSV vazio");

  const header = splitLinha(linhasTexto[0]);
  if (JSON.stringify(header) !== JSON.stringify(COLUNAS)) {
    throw new Error(`colunas inesperadas: ${header.join(" | ")}`);
  }
  if (linhasTexto.length === 1) {
    return { lancamentos: [], cancelados: [], avisos: [], resumo: { total: 0, quantidade: 0 } };
  }

  let linhas = linhasTexto.slice(1).map((texto, i) => {
    const campos = splitLinha(texto);
    if (campos.length !== COLUNAS.length) {
      throw new Error(`linha ${i + 2}: esperadas ${COLUNAS.length} colunas, vieram ${campos.length}`);
    }
    const obj = Object.fromEntries(COLUNAS.map((c, j) => [c, campos[j]]));
    obj._valor = Number(obj["Valor (em R$)"]);
    if (Number.isNaN(obj._valor)) throw new Error(`linha ${i + 2}: valor inválido "${obj["Valor (em R$)"]}"`);
    paraData(obj["Data de Compra"]);
    return obj;
  });

  // Regra: Inclusao de Pagamento é ignorado
  linhas = linhas.filter((l) => l["Descrição"] !== "Inclusao de Pagamento");

  // Regra: cancelamento 1:1 de estornos e do par Anuidade/Estorno Tarifa
  const { mantidos, cancelados } = cancelarPares(linhas);

  const avisos = [];
  const lancamentos = mantidos.map((l) => {
    const categoria = categorizar(l["Descrição"], dicionario);
    let idMeta = "";
    if (categoria.startsWith("Meta: ")) {
      const nomeMeta = categoria.slice(6);
      if (metas.some((m) => m.nome === nomeMeta)) idMeta = nomeMeta;
      else avisos.push(`meta não encontrada para categoria "${categoria}"`);
    }
    const sufixo = l["Parcela"] !== "Única" ? ` (${l["Parcela"]})` : "";
    // Convenção canônica do projeto: valor sempre positivo, direção em tipo
    return {
      data_competencia: vencimento,
      data_original: l["Data de Compra"],
      descricao: l["Descrição"] + sufixo,
      titulo: "",
      valor: Math.abs(l._valor),
      categoria,
      tipo: l._valor < 0 ? "entrada" : "saída",
      origem: "cartao",
      status: "confirmado",
      id_meta: idMeta,
    };
  });

  const datas = mantidos.map((l) => paraData(l["Data de Compra"]));
  const fmt = (d) => d.toLocaleDateString("pt-BR");
  const resumo = {
    quantidade: lancamentos.length,
    // total líquido da fatura: saídas menos créditos mantidos
    total: Math.round(
      lancamentos.reduce((s, l) => s + (l.tipo === "saída" ? l.valor : -l.valor), 0) * 100
    ) / 100,
    periodo_inicio: datas.length ? fmt(new Date(Math.min(...datas))) : "",
    periodo_fim: datas.length ? fmt(new Date(Math.max(...datas))) : "",
    vencimento,
    pares_cancelados: cancelados.length,
  };
  return { lancamentos, cancelados, avisos, resumo };
}

/**
 * Normaliza uma data vinda da planilha para a chave canônica "DD/MM/YYYY".
 * Aceita os três formatos que o nó googleSheets pode devolver:
 *   - "DD/MM/YYYY" (string) → como está;
 *   - "YYYY-MM-DD" (string ISO) → reordena;
 *   - serial do Sheets (número ou string só-dígitos; dias desde 1899-12-30).
 * Qualquer outra coisa → null (linha ignorada no cálculo, não trava).
 */
function normalizarData(v) {
  if (v === null || v === undefined || v === "") return null;
  if (typeof v === "number" || (typeof v === "string" && /^\d+(\.\d+)?$/.test(v.trim()))) {
    const serial = Math.floor(Number(v));
    if (!Number.isFinite(serial) || serial <= 0) return null;
    const d = new Date(Date.UTC(1899, 11, 30) + serial * 86400000);
    const dd = String(d.getUTCDate()).padStart(2, "0");
    const mm = String(d.getUTCMonth() + 1).padStart(2, "0");
    return `${dd}/${mm}/${d.getUTCFullYear()}`;
  }
  const s = String(v).trim();
  let m;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[1]}/${m[2]}/${m[3]}`;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[3]}/${m[2]}/${m[1]}`;
  return null;
}

/**
 * Decide se a fatura (identificada pelo vencimento) já está na planilha.
 * @param {{origem, data_competencia}[]} existentes linhas atuais de Lançamentos
 * @param {string} vencimentoDDMMYYYY vencimento do arquivo (vencimentoDoNome → DD/MM/YYYY)
 * @returns {{bloqueada: boolean, quantidade: number}}
 */
function faturaJaImportada(existentes, vencimentoDDMMYYYY) {
  const alvo = normalizarData(vencimentoDDMMYYYY);
  const quantidade = (existentes || []).filter(
    (r) => String(r.origem) === "cartao" && normalizarData(r.data_competencia) === alvo
  ).length;
  return { bloqueada: quantidade > 0, quantidade };
}

// Mapeamento puro entre o shape "flat" usado pela lógica de negócio reaproveitada de
// workflows/src/*.js (parser-cartao, parser-conta, dashboard, rateio, ...) e o formato
// de properties da API do Notion (POST /v1/pages, POST /v1/databases/{id}/query).
// Sem I/O — só transformação de dados. Concatenado nos Code nodes do n8n junto com
// os módulos puros originais (ver scripts/gerar-workflow-*-notion.js).
// Implementa a Fase A de gstack (schema em workflows-harumi/README... ver plano da branch).

/** "DD/MM/YYYY" ou "YYYY-MM-DD" → "YYYY-MM-DD" (Notion exige ISO); inválido/vazio → null. */
function paraIso(data) {
  if (data === null || data === undefined || data === "") return null;
  const s = String(data).trim();
  let m;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[1]}-${m[2]}-${m[3]}`;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
}

/**
 * Texto plano de uma property title/rich_text do Notion. As demais funções de
 * leitura (paraObjeto*) devolvem "YYYY-MM-DD" para datas — mesDe()/normalizarData()
 * em workflows/src/*.js já aceitam esse formato ISO nativamente, então nenhuma
 * conversão adicional é necessária na leitura (só na escrita, via paraIso).
 */
function textoDe(prop) {
  if (!prop) return "";
  const arr = prop.title || prop.rich_text || [];
  return arr.map((t) => t.plain_text || "").join("");
}

const richText = (s) => (s ? [{ text: { content: String(s).slice(0, 2000) } }] : []);
const selectOrNull = (s) => (s ? { select: { name: String(s) } } : { select: null });
const dateOrNull = (isoOuBr) => {
  const iso = paraIso(isoOuBr);
  return iso ? { date: { start: iso } } : { date: null };
};

// ─── Lançamentos ────────────────────────────────────────────────────────────

/** Page do Notion (results[i] de um query em Lançamentos) → objeto flat esperado pelos parsers/dashboard. */
function paraObjetoLancamento(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    data_competencia: (p["Data Competência"] && p["Data Competência"].date && p["Data Competência"].date.start) || "",
    data_original: (p["Data Original"] && p["Data Original"].date && p["Data Original"].date.start) || "",
    descricao: textoDe(p["Descrição"]),
    titulo: "",
    valor: (p["Valor"] && p["Valor"].number) || 0,
    categoria: (p["Categoria"] && p["Categoria"].select && p["Categoria"].select.name) || "",
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    id_meta: textoDe(p["Meta"]),
  };
}

/** Objeto flat (saída do parser-cartao/parser-conta) → properties para criar a page no Notion. */
function propsDeLancamento(l) {
  return {
    "Descrição": { title: richText(l.descricao || l.titulo || "(sem descrição)") },
    "Valor": { number: Number(l.valor) || 0 },
    "Categoria": selectOrNull(l.categoria),
    "Tipo": selectOrNull(l.tipo),
    "Origem": selectOrNull(l.origem),
    "Status": selectOrNull(l.status),
    "Meta": { rich_text: richText(l.id_meta) },
    "Data Competência": dateOrNull(l.data_competencia),
    "Data Original": dateOrNull(l.data_original),
  };
}

/** Update parcial (PATCH) de um Lançamento: só Categoria+Meta — não toca nas demais properties. */
function propsCategoriaEMeta(categoria, idMeta) {
  return { "Categoria": selectOrNull(categoria), "Meta": { rich_text: richText(idMeta) } };
}

// ─── Dicionário ─────────────────────────────────────────────────────────────

function paraObjetoDicionario(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    descricao_original: textoDe(p["Descrição Original"]),
    categoria_mapeada: (p["Categoria Mapeada"] && p["Categoria Mapeada"].select && p["Categoria Mapeada"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

/** Dicionário lido vira { chave, categoria } (contrato de parser-cartao.categorizar / parser-conta). */
function paraDicionarioChaveCategoria(objetosDicionario) {
  return objetosDicionario.map((d) => ({ chave: d.descricao_original, categoria: d.categoria_mapeada }));
}

function propsDeDicionario(d) {
  // Criado Em nunca fica vazio: cai no dia de hoje se d.criado_em não vier preenchido.
  const criadoEm = paraIso(d.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Descrição Original": { title: richText(d.descricao_original || "(vazio)") },
    "Categoria Mapeada": selectOrNull(d.categoria_mapeada),
    "Origem": selectOrNull(d.origem),
    "Criado Em": { date: { start: criadoEm } },
  };
}

// ─── Categorias ─────────────────────────────────────────────────────────────

function paraObjetoCategoria(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    ativo: !!(p["Ativo"] && p["Ativo"].checkbox),
  };
}

function propsDeCategoria(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Tipo": selectOrNull(c.tipo),
    "Ativo": { checkbox: !!c.ativo },
  };
}

// ─── Config ─────────────────────────────────────────────────────────────────

function paraObjetoConfig(page) {
  const p = (page && page.properties) || {};
  return { _id: page && page.id, chave: textoDe(p["Chave"]), valor: textoDe(p["Valor"]) };
}

function propsDeConfig(c) {
  return {
    "Chave": { title: richText(c.chave || "(sem chave)") },
    "Valor": { rich_text: richText(c.valor) },
  };
}

// ─── Log ────────────────────────────────────────────────────────────────────

/** Necessário a partir da Fase B: categorizacao-hibrida lê o Log p/ não perguntar 2x. */
function paraObjetoLog(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    timestamp: (p["Timestamp"] && p["Timestamp"].date && p["Timestamp"].date.start) || "",
    acao: textoDe(p["Ação"]),
    entidade: textoDe(p["Entidade"]),
    valor_anterior: textoDe(p["Valor Anterior"]),
    valor_novo: textoDe(p["Valor Novo"]),
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
  };
}

function propsDeLog(l) {
  const registro = `${l.acao || ""} — ${l.entidade || ""}`.trim();
  return {
    "Registro": { title: richText(registro || "log") },
    "Timestamp": { date: { start: l.timestamp || new Date().toISOString() } },
    "Ação": { rich_text: richText(l.acao) },
    "Entidade": { rich_text: richText(l.entidade) },
    "Valor Anterior": { rich_text: richText(l.valor_anterior) },
    "Valor Novo": { rich_text: richText(l.valor_novo) },
    "Origem": selectOrNull(l.origem),
  };
}


// ── Glue: Dicionário/Lançamentos existentes vêm de 'Ler Dados (Notion)' ──
const entrada = $('Início').first().json;
const brutos = $('Ler Dados (Notion)').first().json;
const dicionario = paraDicionarioChaveCategoria(brutos.dicionario.map(paraObjetoDicionario));
const metas = []; // Fase C adiciona a database Metas no Notion
const existentes = brutos.lancamentos_existentes.map(paraObjetoLancamento);
try {
  const r = processarFatura(String(entrada.csv || ''), String(entrada.nome_arquivo || ''), dicionario, metas);
  const dedup = faturaJaImportada(existentes, r.resumo.vencimento);
  return [{ json: { ok: true, bloqueada: dedup.bloqueada, ja_importadas: dedup.quantidade, ...r } }];
} catch (e) {
  return [{ json: { ok: false, erro: e.message } }];
}

const p = $('Parser Fatura').first().json;
return [{ json: { timestamp: new Date().toISOString(), acao: 'importacao_bloqueada',
  entidade: 'Lançamentos', valor_anterior: 'vencimento ' + p.resumo.vencimento,
  valor_novo: 'fatura ja importada (' + p.ja_importadas + ' lancamentos)',
  origem: 'ingestao-csv-cartao' } }];

